public class ParkingSpot {
  public SpotSize Size { get; }
  public Vehicle CurrentVehicle { get; private set; }

  public void Occupy(Vehicle v) {
    CurrentVehicle = v;
  }
  public void Vacate() {
    CurrentVehicle = null;
  }
  public bool IsAvailable => CurrentVehicle == null;
}

public class ParkingLot {
  private int _totalSpots = 500;
  private int _occupied = 0;

  public void Park() { _occupied++; }
  public void Leave() { _occupied--; }
  public bool IsFull => _occupied >= _totalSpots;
}

public class ParkingTicket {
  public DateTime EntryTime { get; }
  public DateTime? ExitTime { get; set; }
  public ParkingSpot Spot { get; }

  public decimal CalculateFee() {
    var hours = (ExitTime.Value - EntryTime).TotalHours;
    return (decimal)Math.Ceiling(hours) * 5.00m; // $5/hour
  }
}

