public enum VehicleType {
  Motorcycle,
  Car,
  Truck,
  ElectricCar,
  HandicappedVan
}

public class ParkingSpot {
  public bool CanFit(VehicleType type) {
    switch (_spotType) {
      case SpotType.Compact: return type == VehicleType.Motorcycle || type == VehicleType.Car;
      case SpotType.Large: return true;
      case SpotType.Handicapped: return type == VehicleType.HandicappedVan;
      case SpotType.EV: return type == VehicleType.ElectricCar;
      default: return false;
    }
  }
}

public interface IParkingLot {
  Ticket Enter(Vehicle vehicle);
  decimal Exit(Ticket ticket);
  int GetAvailableSpots();
  ParkingSpot FindSpot(Vehicle vehicle);
}

public class ParkingFloor {
  private List<ParkingSpot> _spots;

  public ParkingSpot FindAvailable(VehicleType type) {
    return _spots.FirstOrDefault(s => s.IsAvailable && s.CanFit(type));
  }
}

public class ParkingLot {
  private List<ParkingFloor> _floors;

  public ParkingSpot FindSpot(VehicleType type) {
    foreach (var floor in _floors) {
      var spot = floor.FindAvailable(type);
      if (spot != null) return spot;
    }
    return null;
  }
}

public class ParkingLot {
  public Ticket Enter(Vehicle v) {
    var spot = FindSpot(v);
    if (spot == null) throw new ParkingFullException();
    spot.Occupy(v);
    var ticket = new Ticket(v, spot, DateTime.Now);
    return ticket;
  }

  public decimal Exit(Ticket ticket) {
    ticket.Spot.Vacate();
    ticket.ExitTime = DateTime.Now;
    return _pricing.Calculate(ticket);
  }
}

public class ParkingLot {
  private static ParkingLot _instance;
  public static ParkingLot Instance => _instance ??= new ParkingLot();
